model.ts<pre><code>const ArtisteSchema = new Schema&lt;IArtiste&gt;({
  nom: {
    type: String,
    required: true,
    maxLength: [250, 'La longueur du nom ne doit pas dépasser 250'],
  },
  telephone: {
    type: String,
    validate: {
      validator: function (v) {
